#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int is_coprime(int a, int b) {
    return gcd(a, b) == 1;
}

int is_connected(int* arr, int n) {
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (is_coprime(arr[i], arr[j])) return 1;
        }
    }
    return 0;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int* arr = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        int changes = 0;
        for (int i = 0; i < n; i++) {
            if (!is_connected(arr, n)) {
                arr[i] = 2;
                changes++;
            }
        }
        printf("%d\n", changes);
        for (int i = 0; i < n; i++) {
            printf("%d ", arr[i]);
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

